INSERT INTO pages (slug, title, description, status, content, meta_title, meta_desc, show_in_menu, updated_at)
VALUES (
  'privacy',
  'Privacy Policy',
  'How National Check-In Week collects, uses, and protects your personal information.',
  'published',
  '[
    {"id":"pp-1","type":"html","data":{"html":"<h2>1. Introduction</h2><p>National Check-In Week (\"we\", \"us\", or \"our\") is committed to protecting your personal information in accordance with the <em>Privacy Act 1988</em> (Cth) and the Australian Privacy Principles (APPs). This policy explains how we collect, use, disclose, and safeguard your information when you visit <a href=\"https://nationalcheckinweek.com\">nationalcheckinweek.com</a>.</p><h2>2. Information We Collect</h2><p>We may collect the following types of personal information:</p><ul><li><strong>Contact information</strong> — name, email address, school name, and role when you register for an event or contact us.</li><li><strong>Usage data</strong> — pages visited, time on site, browser type, and referring URL, collected via analytics tools.</li><li><strong>Event registrations</strong> — information you provide when registering for webinars or professional learning sessions.</li></ul><p>We do not knowingly collect personal information from individuals under the age of 18.</p><h2>3. How We Use Your Information</h2><p>We use the information we collect to:</p><ul><li>Process event registrations and send confirmations</li><li>Send updates about National Check-In Week events and resources</li><li>Improve our website and services</li><li>Respond to enquiries and provide support</li><li>Comply with legal obligations</li></ul><p>We will not sell, trade, or rent your personal information to third parties.</p><h2>4. Disclosure of Information</h2><p>We may share your information with trusted third-party service providers who assist us in operating our website and conducting our events (such as HubSpot for event registration), provided they agree to keep this information confidential. We may also disclose information where required by law or to protect the rights, property, or safety of our organisation, participants, or the public.</p><h2>5. Data Storage and Security</h2><p>Your personal information is stored on secure servers hosted within Australia and managed through Supabase. We implement industry-standard security measures including encryption, access controls, and regular security reviews. However, no method of transmission over the internet is 100% secure and we cannot guarantee absolute security.</p><h2>6. Cookies and Analytics</h2><p>Our website uses cookies and similar tracking technologies to analyse site traffic and improve user experience. You can instruct your browser to refuse all cookies or to indicate when a cookie is being sent. However, some site features may not function properly without cookies.</p><h2>7. Your Rights</h2><p>You have the right to:</p><ul><li>Access the personal information we hold about you</li><li>Request correction of inaccurate information</li><li>Request deletion of your personal information (subject to legal obligations)</li><li>Opt out of marketing communications at any time</li></ul><p>To exercise any of these rights, please contact us at <a href=\"mailto:events@nationalcheckinweek.com\">events@nationalcheckinweek.com</a>.</p><h2>8. Third-Party Links</h2><p>Our website may contain links to third-party websites. We have no control over the content or privacy practices of those sites and encourage you to review their privacy policies independently.</p><h2>9. Changes to This Policy</h2><p>We may update this Privacy Policy from time to time. We will notify you of significant changes by posting the new policy on this page with an updated date. Your continued use of the site after changes are posted constitutes acceptance of the updated policy.</p><h2>10. Contact Us</h2><p>If you have questions or complaints about this Privacy Policy or our privacy practices, please contact us:</p><ul><li><strong>Email:</strong> <a href=\"mailto:events@nationalcheckinweek.com\">events@nationalcheckinweek.com</a></li><li><strong>Phone:</strong> <a href=\"tel:1300889018\">1300 889 018</a></li><li><strong>Address:</strong> 4/597 Darling Street, Rozelle NSW 2039, Australia</li></ul><p>If you are not satisfied with our response, you may lodge a complaint with the <a href=\"https://www.oaic.gov.au\" target=\"_blank\" rel=\"noopener noreferrer\">Office of the Australian Information Commissioner (OAIC)</a>.</p>"}}'
  ]'::jsonb,
  'Privacy Policy | National Check-In Week',
  'How National Check-In Week collects, uses, and protects your personal information.',
  false,
  now()
),
(
  'terms',
  'Terms and Conditions',
  'Terms and conditions governing your use of the National Check-In Week website and participation in our events.',
  'published',
  '[
    {"id":"tc-1","type":"html","data":{"html":"<h2>1. Acceptance of Terms</h2><p>By accessing and using the National Check-In Week website at <a href=\"https://nationalcheckinweek.com\">nationalcheckinweek.com</a> (\"Site\"), or by registering for or participating in any National Check-In Week event, you agree to be bound by these Terms and Conditions. If you do not agree, please do not use the Site or participate in our events.</p><h2>2. About National Check-In Week</h2><p>National Check-In Week (\"NCIW\", \"we\", \"us\", or \"our\") is a free initiative operated by Life Skills Group, aimed at improving student wellbeing in Australian schools. Our registered address is 4/597 Darling Street, Rozelle NSW 2039, Australia.</p><h2>3. Use of the Site</h2><p>You agree to use this Site only for lawful purposes and in a manner that does not:</p><ul><li>Infringe the rights of others</li><li>Restrict or inhibit anyone''s use or enjoyment of the Site</li><li>Transmit any unsolicited or unauthorised advertising or promotional material</li><li>Introduce any malware, viruses, or other harmful material</li><li>Attempt to gain unauthorised access to any part of the Site or its related systems</li></ul><h2>4. Event Participation</h2><p>All events offered through National Check-In Week are provided free of charge to eligible Australian school leaders, educators, and wellbeing professionals. By registering for an event, you agree to:</p><ul><li>Provide accurate registration information</li><li>Use event access links solely for your own attendance</li><li>Not record, reproduce, or distribute event content without our prior written consent</li><li>Conduct yourself professionally and respectfully during all sessions</li></ul><p>We reserve the right to cancel or reschedule events. Registered participants will be notified by email where possible.</p><h2>5. Intellectual Property</h2><p>All content on this Site — including text, data, graphics, logos, icons, images, audio clips, and software — is the property of National Check-In Week or its content suppliers and is protected by Australian and international copyright law. You may not reproduce, distribute, or create derivative works from any content on this Site without our express written permission.</p><h2>6. Data and Statistics</h2><p>Wellbeing data, statistics, and insights presented on this Site are derived from anonymised and aggregated sources, including the Life Skills GO platform. While we take care to ensure accuracy, this information is provided for general educational purposes only and should not be relied upon as professional advice.</p><h2>7. Disclaimers and Limitation of Liability</h2><p>This Site and all content are provided \"as is\" without warranty of any kind, either express or implied. To the maximum extent permitted by applicable law, we exclude all liability for any loss or damage arising from your use of the Site or reliance on any information contained on it.</p><h2>8. Governing Law</h2><p>These Terms are governed by the laws of New South Wales, Australia. Any disputes arising under these Terms are subject to the exclusive jurisdiction of the courts of New South Wales.</p><h2>9. Contact Us</h2><p>For questions about these Terms, please contact us:</p><ul><li><strong>Email:</strong> <a href=\"mailto:events@nationalcheckinweek.com\">events@nationalcheckinweek.com</a></li><li><strong>Phone:</strong> <a href=\"tel:1300889018\">1300 889 018</a></li><li><strong>Address:</strong> 4/597 Darling Street, Rozelle NSW 2039, Australia</li></ul>"}}'
  ]'::jsonb,
  'Terms and Conditions | National Check-In Week',
  'Terms and conditions governing your use of the National Check-In Week website and participation in our events.',
  false,
  now()
);

COMMIT;
